jQuery(function() {
  jQuery('#the-list').on('click', '.editinline', function() {
    jQuery('.inline-edit-author').length &&
      jQuery('.inline-edit-author-new').length &&
      (jQuery('.inline-edit-author').hide(),
      jQuery('.inline-edit-author').attr('class', 'inline-edit-author-old'),
      jQuery('select[name=post_author]').attr('name', 'post_author-old'),
      jQuery('select[name=post_author-new]').attr('name', 'post_author'))
    let e = jQuery(this)
      .closest('tr')
      .attr('id')
    e = e.replace('post-', '')
    var r,
      n,
      t = jQuery('#vendor_' + e),
      a = jQuery('#woocommerce_inline_' + e),
      i = jQuery.trim(t.find('.post_author').text()),
      t = jQuery.trim(t.find('.post_author_name').text()),
      a = a.find('.product_type').val()
    'simple' === a || 'external' === a
      ? jQuery('.vendor', '.inline-edit-row').show()
      : jQuery('.vendor', '.inline-edit-row').hide(),
      (r = i),
      (n = t),
      setTimeout(function() {
        var e,
          t = jQuery('#post_author-new')
        t.data('select2') ||
          t.select2({
            dropdownParent: jQuery(document.body),
            minimumInputLength: 1,
            ajax: {
              delay: 300,
              url: ajaxurl,
              type: 'POST',
              dataType: 'json',
              data: function(e) {
                return {
                  action: 'wcv_search_vendors',
                  term: e.term,
                  _ajax_nonce: wcv_quick_edit_params.vendor_search_nonce
                }
              }
            }
          }),
          t.find('option').remove(),
          r &&
            n &&
            ((e = new Option(n, r, !0, !0)), t.append(e).trigger('change'))
      }, 0)
  }),
    jQuery(document).ready(function() {
      var e = jQuery('.featured input[name="_featured"]'),
        t = jQuery('select.featured').closest('label')
      'no' === wcv_quick_edit_params.allow_featured &&
        (e.parent().hide(), t.hide())
    })
})
